#include <stdio.h>
#include <math.h>

/* Definicija tacke i kruznice */
struct Tacka {
    double x, y;
};

struct Kruznica {
    struct Tacka centar;
    double poluprecnik;
};

/* Funkcija za unos tacke (preko pokazivaca) */
void unos_tacke(struct Tacka* t) {
    printf("Unesite koordinate tacke (x,y): ");
    scanf("%lf,%lf", &t->x, &t->y);
}

/* Funkcija za unos kruznice (preko pokazivaca) */
void unos_kruznice(struct Kruznica* k) {
    printf("Unesite centar kruznice:\n");
    unos_tacke(&k->centar);

    printf("Unesite poluprecnik kruznice: ");
    scanf("%lf", &k->poluprecnik);
}

/* Funkcija za udaljenost izmedju dvije tacke (preko pokazivaca) */
double udaljenost(const struct Tacka* t1, const struct Tacka* t2) {
    return sqrt(
        (t1->x - t2->x) * (t1->x - t2->x) + (t1->y - t2->y) * (t1->y - t2->y)
    );
}

/* Glavni program: Da li je tacka unutar kruznice */
int main() {
    struct Kruznica k;
    struct Tacka t;
    double d;
    const double EPS = 0.0001;

    printf("Unesite kruznicu:\n");
    unos_kruznice(&k);

    printf("Unesite neku tacku:\n");
    unos_tacke(&t);

    /* Provjera polozaja tacke u odnosu na kruznicu */
    d = udaljenost(&t, &k.centar);

    if (d < k.poluprecnik - EPS)
        printf("Tacka je unutar kruznice.");
    else if (fabs(d - k.poluprecnik) < EPS)
        printf("Tacka je na kruznici.");
    else
        printf("Tacka je izvan kruznice.");

    return 0;
}
